import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const x=JSON.parse('{"title":"司马台长城","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/simatai.md","filePath":"landmarks/simatai.md","lastUpdated":null}'),n={name:"landmarks/simatai.md"};function o(i,t,d,s,h,g){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="司马台长城" tabindex="-1">司马台长城 <a class="header-anchor" href="#司马台长城" aria-label="Permalink to &quot;司马台长城&quot;">​</a></h1><blockquote><p>&quot;中国长城之最，原始风貌的绝佳体验。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>司马台长城位于北京市密云区，距北京城区120公里，是万里长城中最险要的一段，被誉为&quot;中国长城之最&quot;。司马台长城以&quot;惊、险、奇&quot;著称，保留了明长城的原始风貌。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">8:00-17:00（日游），17:30-21:00（夜游）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">门票40元，索道往返160元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">半天至一天</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">春秋两季，夜游长城独特</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">东直门旅游专线或自驾</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市密云区古北口镇司马台村</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="始建" tabindex="-1">始建 <a class="header-anchor" href="#始建" aria-label="Permalink to &quot;始建&quot;">​</a></h3><p>司马台长城始建于明洪武年间（1368-1398年），由大将戚继光主持修建。戚继光在任蓟镇总兵期间，对长城进行了大规模整修和加固。</p><h3 id="建筑特点" tabindex="-1">建筑特点 <a class="header-anchor" href="#建筑特点" aria-label="Permalink to &quot;建筑特点&quot;">​</a></h3><p>司马台长城充分体现了戚继光的军事防御思想，敌楼设计巧妙，城墙修建坚固。历经400余年风雨，司马台长城保存相对完整，保留了明长城的原始风貌。</p><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="惊" tabindex="-1">惊 <a class="header-anchor" href="#惊" aria-label="Permalink to &quot;惊&quot;">​</a></h3><p>司马台长城依山势而建，最险处坡度达85度，几近垂直。登城如同登天梯，惊心动魄。</p><h3 id="险" tabindex="-1">险 <a class="header-anchor" href="#险" aria-label="Permalink to &quot;险&quot;">​</a></h3><p>城墙建于悬崖峭壁之上，两侧都是深谷，走在这座城墙上需要极大勇气。</p><h3 id="奇" tabindex="-1">奇 <a class="header-anchor" href="#奇" aria-label="Permalink to &quot;奇&quot;">​</a></h3><p>司马台长城的敌楼设计独特，有单眼楼、双眼楼、三眼楼、四眼楼、五眼楼之分，形式多样，堪称长城敌楼博物馆。</p><h2 id="敌楼类型" tabindex="-1">敌楼类型 <a class="header-anchor" href="#敌楼类型" aria-label="Permalink to &quot;敌楼类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">类型</th><th style="text-align:left;">特点</th><th style="text-align:center;">数量</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>单眼楼</strong></td><td style="text-align:left;">单孔箭窗</td><td style="text-align:center;">多座</td></tr><tr><td style="text-align:left;"><strong>双眼楼</strong></td><td style="text-align:left;">双孔箭窗</td><td style="text-align:center;">多座</td></tr><tr><td style="text-align:left;"><strong>三眼楼</strong></td><td style="text-align:left;">三孔箭窗</td><td style="text-align:center;">多座</td></tr><tr><td style="text-align:left;"><strong>四眼楼</strong></td><td style="text-align:left;">四孔箭窗</td><td style="text-align:center;">多座</td></tr><tr><td style="text-align:left;"><strong>五眼楼</strong></td><td style="text-align:left;">五孔箭窗，长城中罕见</td><td style="text-align:center;">1座</td></tr></tbody></table><h2 id="游览区域" tabindex="-1">游览区域 <a class="header-anchor" href="#游览区域" aria-label="Permalink to &quot;游览区域&quot;">​</a></h2><h3 id="东段-推荐" tabindex="-1">东段（推荐） <a class="header-anchor" href="#东段-推荐" aria-label="Permalink to &quot;东段（推荐）&quot;">​</a></h3><p>东段是司马台长城的精华所在，也是最险峻的部分。从1号敌楼至10号敌楼，沿途风景壮丽，惊险刺激。</p><h4 id="仙女楼" tabindex="-1">仙女楼 <a class="header-anchor" href="#仙女楼" aria-label="Permalink to &quot;仙女楼&quot;">​</a></h4><p>仙女楼是司马台长城的标志性建筑，位于海拔约500米的悬崖之上，造型优美，传说有仙女在此居住。</p><h4 id="望京楼" tabindex="-1">望京楼 <a class="header-anchor" href="#望京楼" aria-label="Permalink to &quot;望京楼&quot;">​</a></h4><p>望京楼是司马台长城的最高点，海拔986米。天气晴好时，站在望京楼上可以远眺北京城，故名&quot;望京&quot;。</p><h3 id="西段" tabindex="-1">西段 <a class="header-anchor" href="#西段" aria-label="Permalink to &quot;西段&quot;">​</a></h3><p>西段相对平缓，适合体力一般的游客。可乘坐索道上山，游览部分敌楼后原路返回。</p><h2 id="夜游长城" tabindex="-1">夜游长城 <a class="header-anchor" href="#夜游长城" aria-label="Permalink to &quot;夜游长城&quot;">​</a></h2><p>司马台长城是全国唯一开放夜游的长城。夜晚登城，提灯而行，别有一番风味。</p><h3 id="夜游亮点" tabindex="-1">夜游亮点 <a class="header-anchor" href="#夜游亮点" aria-label="Permalink to &quot;夜游亮点&quot;">​</a></h3><ul><li><strong>提灯夜游</strong>：提灯漫步长城，体验古人守边关的感觉</li><li><strong>星空观赏</strong>：远离城市光污染，仰望星空</li><li><strong>古北水镇</strong>：夜游后可到古北水镇泡温泉</li></ul><h3 id="夜游时间" tabindex="-1">夜游时间 <a class="header-anchor" href="#夜游时间" aria-label="Permalink to &quot;夜游时间&quot;">​</a></h3><p>夜游长城开放时间为每年4月至10月，具体时间以景区公告为准。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>日游路线（约4-5小时）</strong>：</p><p>乘索道至5号敌楼 → 游览东段至10号敌楼 → 返回5号敌楼 → 乘索道下山</p><p><strong>夜游路线（约2-3小时）</strong>：</p><p>乘索道上山 → 游览部分敌楼 → 观星赏夜景 → 乘索道下山 → 古北水镇泡温泉</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th><th style="text-align:center;">时间</th><th style="text-align:center;">费用</th></tr></thead><tbody><tr><td style="text-align:left;">旅游专线</td><td style="text-align:left;">东直门 → 司马台</td><td style="text-align:center;">约2.5小时</td><td style="text-align:center;">约50元</td></tr><tr><td style="text-align:left;">自驾</td><td style="text-align:left;">京承高速 → 司马台出口</td><td style="text-align:center;">约2小时</td><td style="text-align:center;">-</td></tr><tr><td style="text-align:left;">包车</td><td style="text-align:left;">市区往返</td><td style="text-align:center;">约2小时</td><td style="text-align:center;">600-800元</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>体力要求</strong>：司马台长城较险，需要较好体力</li><li><strong>夜游准备</strong>：夜游需带外套，山顶风大</li><li><strong>索道时间</strong>：注意索道末班车时间</li><li><strong>结合游玩</strong>：建议与古北水镇一起游览</li><li><strong>安全注意</strong>：部分路段较险，注意安全</li></ol><h2 id="古北水镇" tabindex="-1">古北水镇 <a class="header-anchor" href="#古北水镇" aria-label="Permalink to &quot;古北水镇&quot;">​</a></h2><p>司马台长城脚下的古北水镇是近年来新建的仿古建筑群，集观光、休闲、度假于一体。</p><h3 id="水镇特色" tabindex="-1">水镇特色 <a class="header-anchor" href="#水镇特色" aria-label="Permalink to &quot;水镇特色&quot;">​</a></h3><ul><li><strong>仿古建筑</strong>：仿照明清风格建造</li><li><strong>温泉</strong>：地下温泉资源丰富</li><li><strong>夜景</strong>：夜景灯光秀</li><li><strong>美食</strong>：北方特色小吃</li></ul><h3 id="推荐行程" tabindex="-1">推荐行程 <a class="header-anchor" href="#推荐行程" aria-label="Permalink to &quot;推荐行程&quot;">​</a></h3><p><strong>两天一夜</strong>：</p><ul><li>Day1：下午抵达古北水镇 → 游览水镇 → 夜游司马台长城 → 温泉</li><li>Day2：日游司马台长城 → 午餐后返程</li></ul><hr><p><strong>📍 地址</strong>：北京市密云区古北口镇司马台村 <strong>📞 电话</strong>：010-81009999 <strong>🌐 官网</strong>：<a href="http://www.wtown.com" target="_blank" rel="noreferrer">www.wtown.com</a></p>',54)])])}const u=a(n,[["render",o]]);export{x as __pageData,u as default};
